async function getData() {
  // Fetch the quote from the dummyjson API
  const response = await fetch("https://dummyjson.com/quotes/1");

  // Converts the response into a JavaScript object
  const data = await response.json();

  // Print the quote to the output
  console.log(data.quote);
}

// Runs the function above
getData();

